    treeConfig: TAccountMetas[4];
    merkleTree: TAccountMetas[5];
    coreCollection: TAccountMetas[6];
    mplCoreCpiSigner: TAccountMetas[7];
    logWrapper: TAccountMetas[8];
    compressionProgram: TAccountMetas[9];
